def research_design_audit_gate(design):
    # D1: C-TOTALITY - ensure design is a dict
    if not isinstance(design, dict):
        return {"may_proceed": False, "reason": "Design must be a dictionary."}

    audit_findings = design.get("audit_findings", [])

    # D2: Validate MAJOR findings - must have valid disposition (not OPEN, not missing)
    for finding in audit_findings:
        # Check if finding is a dict
        if not isinstance(finding, dict):
            return {"may_proceed": False, "reason": "All audit findings must be dictionaries."}

        severity = finding.get("severity")
        if severity == "MAJOR":
            # Must have 'disposition' key
            if "disposition" not in finding:
                return {"may_proceed": False, "reason": "MAJOR finding missing 'disposition' key."}

            disposition = finding.get("disposition")
            # Must be one of the allowed dispositions and NOT 'OPEN'
            if disposition not in ["RESOLVED", "REJECTED", "MOVED_TO_GAP"]:
                return {"may_proceed": False, "reason": "MAJOR finding has invalid or OPEN disposition."}

    # D3: If any finding is RESOLVED, revision_ref must be non-empty
    has_resolved = any(
        isinstance(f, dict) and f.get("disposition") == "RESOLVED"
        for f in audit_findings
    )
    if has_resolved:
        revision_ref = design.get("revision_ref", "")
        if not isinstance(revision_ref, str) or len(revision_ref.strip()) == 0:
            return {"may_proceed": False, "reason": "RESOLVED findings require a non-empty revision_ref."}

    # D4: rq_candidates must be a non-empty list
    rq_candidates = design.get("rq_candidates", [])
    if not isinstance(rq_candidates, list) or len(rq_candidates) == 0:
        return {"may_proceed": False, "reason": "rq_candidates must be a non-empty list."}

    return {"may_proceed": True, "reason": "All audit requirements satisfied."}
